// Traffic Light — parametric vertical signal head
// ------------------------------------------------
// A three-lamp traffic signal: a rounded housing with red / amber / green
// lenses recessed into the face, optional sun visors hooding each lamp, and an
// optional mounting post + base. Every region is api.label()'d so the colors
// (dark housing, R/A/G lenses, visors, post) can be painted by label.
//
// Knobs are exposed through api.params(...) so the whole signal drops straight
// into the Customizer panel. Defaults are tuned to read well as a catalog tile.

const { Manifold, CrossSection } = api;

const p = api.params({
  lampDiameter: { type: 'number',  default: 26, min: 12, max: 48, step: 1, unit: 'mm',
                  label: 'Lamp diameter', help: 'Diameter of each round lens.' },
  lampSpacing:  { type: 'number',  default: 34, min: 20, max: 60, step: 1, unit: 'mm',
                  label: 'Lamp spacing', help: 'Center-to-center distance between lamps.' },
  margin:       { type: 'number',  default: 9,  min: 4,  max: 24, step: 1, unit: 'mm',
                  label: 'Housing margin', help: 'Border of housing around the lamps.' },
  cornerRadius: { type: 'number',  default: 6,  min: 0,  max: 16, step: 1, unit: 'mm',
                  label: 'Corner radius', help: 'Rounding of the housing corners.' },
  visors:       { type: 'boolean', default: true,  label: 'Sun visors',
                  help: 'Curved hoods over each lamp.' },
  visorDepth:   { type: 'number',  default: 14, min: 4,  max: 30, step: 1, unit: 'mm',
                  label: 'Visor depth', help: 'How far the visors stick out (when enabled).' },
  post:         { type: 'boolean', default: true,  label: 'Mounting post',
                  help: 'Vertical pole and base below the housing.' },
  postHeight:   { type: 'number',  default: 70, min: 20, max: 160, step: 2, unit: 'mm',
                  label: 'Post height', help: 'Length of the pole (when enabled).' },
});

// ---- derived dimensions -------------------------------------------------
const lampR     = p.lampDiameter / 2;
const lensDepth = Math.max(2, lampR * 0.32);     // dome height of each lens
const recess    = lensDepth * 0.55;              // how deep the cavity is bored
const margin    = Math.max(p.margin, p.cornerRadius + 1); // keep corners inside the face
// Housing must fit 3 lamps stacked vertically plus margins.
const innerH    = 2 * p.lampSpacing + p.lampDiameter; // span from top lamp top to bottom lamp bottom
const W = p.lampDiameter + 2 * margin;                 // housing width  (X)
const H = innerH + 2 * margin;                         // housing height (Z)
const D = Math.max(14, p.lampDiameter * 0.7);          // housing depth  (Y)
const cr = Math.min(p.cornerRadius, W / 2 - 0.5, D / 2 - 0.5); // clamp radius

// Lamp centers on Z, top -> bottom: red, amber, green.
const lampZ = [ p.lampSpacing, 0, -p.lampSpacing ]; // before lifting whole housing
const lampColors = ['lampRed', 'lampAmber', 'lampGreen'];
const faceY = D / 2;                              // front face plane (+Y)

// ---- rounded housing body ----------------------------------------------
// Rounded-rectangle prism via Minkowski-style offset on a 2D profile, then
// extrude along Z. Falls back to a plain box when cornerRadius == 0.
function roundedBody() {
  if (cr <= 0) return Manifold.cube([W, D, H], true);
  const core = CrossSection.square([W - 2 * cr, D - 2 * cr], true).offset(cr);
  return core.extrude(H, undefined, undefined, undefined, true); // centered on Z
}

let housing = roundedBody();

// ---- bore the lamp recesses into the front face ------------------------
// A short cylinder sunk into +Y so each lens sits in a dished pocket.
for (const z of lampZ) {
  const cavity = Manifold.cylinder(recess + 1, lampR, lampR)
    .rotate([-90, 0, 0])                          // axis -> +Y
    .translate([0, faceY - recess + 1, z]);
  housing = housing.subtract(cavity);
}

housing = api.label(housing, 'housing');

// ---- the three lenses ---------------------------------------------------
// Each lens = a flattened dome (squashed sphere) seated in its recess, pushed
// in by `recess - 0.6` so it overlaps the housing wall by ~0.6mm (fuses) and
// still bulges proud of the face.
const lenses = lampZ.map((z, i) => {
  const dome = Manifold.sphere(lampR)
    .scale([1, lensDepth / lampR, 1])             // squash along Y into a dome
    .translate([0, faceY - recess + lensDepth - 0.6, z]);
  // keep only the part in front of the recess floor so it reads as a lens, not a ball
  const clipped = dome.subtract(
    Manifold.cube([W + 4, recess + 2, H + 4], true)
      .translate([0, faceY - recess - (recess + 2) / 2, 0])
  );
  return api.label(clipped, lampColors[i]);
});

let model = lenses.reduce((acc, l) => acc.add(l), housing);

// ---- optional sun visors ------------------------------------------------
// A visor = a half-tube hood: an outer arc shell, hollowed, clipped to the top
// half, tilted down slightly, and parked over each lamp's front rim.
if (p.visors) {
  const vR   = lampR + 2.5;                       // hood radius a touch over the lens
  const vTh  = 2.2;                               // shell thickness
  const len  = p.visorDepth;                      // forward projection
  // tube along Y (depth), centered; outer minus inner.
  const tube = Manifold.cylinder(len, vR, vR, undefined)
    .subtract(Manifold.cylinder(len + 2, vR - vTh, vR - vTh).translate([0, 0, -1]))
    .rotate([-90, 0, 0]);                          // axis -> +Y, base at y=0
  // keep the top hemisphere of the tube (a hood, open below)
  const hood = tube.subtract(
    Manifold.cube([2 * vR + 4, len + 4, 2 * vR + 4], true).translate([0, len / 2, -vR])
  );
  let visorParts = null;
  for (const z of lampZ) {
    let v = hood.rotate([12, 0, 0])              // tip the brim downward
              .translate([0, faceY - 0.5, z]);    // overlap face by 0.5 to fuse
    visorParts = visorParts === null ? v : visorParts.add(v);
  }
  model = model.add(api.label(visorParts, 'visors'));
}

// ---- optional mounting post + base -------------------------------------
if (p.post) {
  const poleR = Math.max(4, W * 0.16);
  const baseR = poleR * 2.0;
  const baseH = Math.max(4, poleR);
  const bottomZ = -H / 2;                          // housing bottom
  // Base sits at the very bottom; pole spans from inside the base all the way
  // up into the housing bottom so all three (base/pole/housing) overlap & fuse.
  const baseBottom = bottomZ - p.postHeight - baseH; // lowest point of the whole part
  const base = Manifold.cylinder(baseH, baseR, baseR * 0.85)
    .translate([0, 0, baseBottom]);
  const poleBottom = baseBottom + baseH - 1;        // start 1mm inside the base top
  const poleTop = bottomZ + 4;                      // poke 4mm up into the housing
  const pole = Manifold.cylinder(poleTop - poleBottom, poleR, poleR)
    .translate([0, 0, poleBottom]);
  const postPart = api.label(pole.add(base), 'post');
  model = model.add(postPart);
  // lift everything so the base sits on z=0 (nice for the tile + printing)
  model = model.translate([0, 0, -baseBottom]);
} else {
  // no post: rest the housing on z=0
  model = model.translate([0, 0, H / 2]);
}

return model;

